          {cfg.seats&&<span style={{color:C.muted,fontSize:12}}>· {cfg.seats}</span>}
          {cfg.bodyColor&&<span style={{display:"flex",alignItems:"center",gap:5}}><span style={{width:11,height:11,borderRadius:"50%",background:cfg.bodyColor.hex,border:"1px solid #555",display:"inline-block"}}/><span style={{color:C.muted,fontSize:11}}>{cfg.bodyColor.code}</span></span>}
